def send_discord_alert(webhook_url, title, message, color=0xff3030):
    if not webhook_url:
        return
    import time as _t2
    payload = {"embeds": [{"title": title, "description": message, "color": color,
        "footer": {"text": "RavenMiner HQ 3.9.0 RC2 • " + _t2.strftime("%H:%M:%S")}}]}
    def _post():
        try: requests.post(webhook_url, json=payload, timeout=6)
        except Exception as ex: print("Discord webhook error:", ex)
    import threading as _th
    _th.Thread(target=_post, daemon=True).start()

